  ('social-worker-moex-00011', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '在女性主義理論中，主張要分離「個人即政治」的說法，強調差異、看重認同，反對模仿男性生 活方式，倡議發揮新的女性力量的觀點，屬於下列何者？', '["自由主義的女性主義", "社會主義的女性主義", "基進女性主義", "後現代女性主義"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:00+00:00", "source_pdf_sha1": "461402c5eeb6", "answer_pdf_sha1": "97eeea6c0c9c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00012', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關皮亞傑（Piaget）具體運思期的主張，下列敘述何者錯誤？', '["無法以邏輯做正式的運思", "無法將理想和現實做比較", "無法進行假設性思考", "無法進行可逆性思考"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:00+00:00", "source_pdf_sha1": "461402c5eeb6", "answer_pdf_sha1": "97eeea6c0c9c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00013', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關一般嬰兒發展的順序，下列敘述何者正確？', '["獨自坐著→獨自行走→獨自站立→牙牙學語", "四肢著地爬行→遵循指示的方向→獨自站立→獨自行走", "大笑→經由協助而站立→獨自行走→學會使用句子", "牙牙學語→獨立坐著→學會使用句子→獨立站立"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:00+00:00", "source_pdf_sha1": "461402c5eeb6", "answer_pdf_sha1": "97eeea6c0c9c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00014', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '為協助長者能達到圓滿的發展任務，下列敘述何者錯誤？', '["協助長輩整理照片、製作生命故事書", "避免讓長輩外出，減少跌倒受傷危險", "提供工具性日常生活活動功能的協助", "協助長輩訂定預立醫療照護指示"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:00+00:00", "source_pdf_sha1": "461402c5eeb6", "answer_pdf_sha1": "97eeea6c0c9c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00015', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '保密是社會工作者在服務中需要遵循的倫理原則，與青少年工作也會遇到相關的議題，下列何者 是社會工作者正確的作為？', '["社會工作者服務青少年時，為尊重青少年的隱私權，不可將青少年的求助議題告知其家長，例 如：性問題、物質濫用", "社會工作者必須了解法規規定，依法尊重青少年的隱私權", "為了與青少年建立良好關係及保護青少年的隱私，社會工作者需考慮不要撰寫和留下紀錄", "當青少年涉及有害健康的行為時，社會工作者應秉持尊重隱私權為先的立場來決定是否通報"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:00+00:00", "source_pdf_sha1": "461402c5eeb6", "answer_pdf_sha1": "97eeea6c0c9c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00016', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '同儕團體對兒童心理社會的發展具有重要影響力，兒童透過同儕團體的學習，下列何者最為適當？', '["認識團體中的領導者", "學會欣賞同儕不同的觀點", "符合同儕團體的角色期待", "認同同儕團體的主流文化"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:00+00:00", "source_pdf_sha1": "461402c5eeb6", "answer_pdf_sha1": "97eeea6c0c9c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00017', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '中年期常被稱為三明治世代，一方面需要養育子女，另一方面要因應父母年老的需求。社會工作 者協助這些中年期的家庭照顧者提升因應能力時，下列何種作為錯誤？', '["帶領支持團體提供照顧者所需要的喘息", "傾聽這些家庭照顧者對於他們所處情境所賦予的意義和看法", "讓家庭照顧者知道他們沒有責任", "強化照顧者對社會資源的認識和使用"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:00+00:00", "source_pdf_sha1": "461402c5eeb6", "answer_pdf_sha1": "97eeea6c0c9c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00018', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '鼓勵長者參與志願服務有助其身心健康，有關長者參與志願服務的功能，下列何者正確？', '["讓長者能夠得到額外收入", "提供長者有意義的社會角色", "強化長者的自我中心意識", "強化長者的現實感"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:00+00:00", "source_pdf_sha1": "461402c5eeb6", "answer_pdf_sha1": "97eeea6c0c9c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00019', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列何者不屬於「工具性日常生活活動（instrumentalactivitiesofdailyliving,IADL）」的內容？', '["外出活動、上街購物", "食物烹調、家務維持", "沐浴穿衣、走路移位", "服用藥物、處理財務"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:00+00:00", "source_pdf_sha1": "461402c5eeb6", "answer_pdf_sha1": "97eeea6c0c9c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00020', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '人類各時期發展之生理層面的特徵與風險，下列何者描述不符合該時期發展？', '["懷孕或新生兒時期常見的風險因素包含早產、子宮外孕、子癲前症等", "青少年時期的生理變化包括賀爾蒙分泌加速、性徵的成熟等", "兒童時期身體才開始發展，包含牙齒、骨骼、肌肉與神經系統等", "成年中期因基礎代謝逐年減緩，較高會面對慢性疾病、心血管或罹患癌症之風險"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:00+00:00", "source_pdf_sha1": "461402c5eeb6", "answer_pdf_sha1": "97eeea6c0c9c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
